export function isActionEnvelopeRelevantToSubscriptionUris(envelope: ActionEnvelope, subscribedUris: Iterable<string>): boolean {
    if (envelope.channel === null || envelope.channel === undefined) {
        return false;
    }

    for (const uri of subscribedUris) {
        if (uri === null || uri === undefined) {
            continue; // Skip invalid URIs
        }

        if (isAhpRootChannel(envelope.channel) && isAhpRootChannel(uri)) {
            return true;
        } else if (envelope.channel === uri) {
            return true;
        }
    }

    return false;
}
```

